mapper.select:
/* GuestRateLimitMapper.selectRateLimit */
SELECT
    ID,
    GUEST_ID,
    MINUTE_KEY,
    COUNT,
    CRE_TM
FROM TB_GUEST_RATE_LIMIT
WHERE GUEST_ID   = #{guestId}
  AND MINUTE_KEY = #{minuteKey}

mapper.update:
/* GuestRateLimitMapper.incrementRateLimit */
UPDATE TB_GUEST_RATE_LIMIT
SET COUNT = COUNT + 1
WHERE GUEST_ID   = #{guestId}
  AND MINUTE_KEY = #{minuteKey}

mapper.delete:
/* GuestRateLimitMapper.deleteOldRateLimits */
DELETE FROM TB_GUEST_RATE_LIMIT
WHERE CREATED_AT  <  NOW() - INTERVAL '1 hour'
